import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';

function App() {
  return (
    <Router>
      <div>
        <h1>School Timetable System</h1>
        <p>Application is working!</p>
      </div>
    </Router>
  );
}

export default App;
